import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HighLowGuessComposer implements IMessageComposer<Array<number>> {
    private _data: Array<number>;

    /**
     * @param choice 1 = HIGH, 2 = LOW
     */
    constructor(choice: number) {
        const safeChoice = choice === 1 || choice === 2 ? choice : 1;
        this._data = [safeChoice];
    }

    public getMessageArray(): Array<number> {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
